import java.util.HashMap;

public boolean possibleDegreeEven(int n, int[][] edges) {
    HashMap<Integer, Integer> degrees = new HashMap<>();
    for (int[] edge : edges) {
        degrees.put(edge[0], degrees.getOrDefault(edge[0], 0) + 1);
        degrees.put(edge[1], degrees.getOrDefault(edge[1], 0) + 1);
    }

    int odd_degrees = 0;
    for (int i = 1; i <= n; i++) {
        if (degrees.getOrDefault(i, 0) % 2 != 0) odd_degrees++;
    }

    return (odd_degrees == 0 || odd_degrees == 2);
}
```

